// ─── v2-all-categories ───────────────────────────────────────────────
// Input: { platform: 'emag'|'trendyol'|'temu', search: 'termen' }
// Output: { categories: [{ id, name }] }  — maxim 50 rezultate
//
// CONFIGURARE (variabile de mediu n8n):
//   EMAG_API_USER, EMAG_API_KEY
//   TRENDYOL_SUPPLIER_ID, TRENDYOL_API_KEY, TRENDYOL_API_SECRET
// ─────────────────────────────────────────────────────────────────────

const body = $input.first().json.body || {};
const platform = (body.platform || 'emag').toLowerCase();
const searchTerm = (body.search || '').toLowerCase().trim();
const MAX_RESULTS = 50;

let categories = [];

try {
  if (platform === 'emag') {
    // ── eMAG Marketplace API ────────────────────────────────────────
    const emagUser = $env['EMAG_API_USER'] || '';
    const emagKey  = $env['EMAG_API_KEY']  || '';
    const authHeader = 'Basic ' + Buffer.from(`${emagUser}:${emagKey}`).toString('base64');

    // Construim filtrele: dacă există search term, filtrăm după nume
    const filters = [
      { name: 'is_leaf', value: 1 }  // doar categorii terminale (cu produse)
    ];

    const data = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://marketplace.emag.ro/api-3/category/read',
      headers: {
        'Authorization': authHeader,
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: {
        filters,
        count: 200,
        currentPage: 1
      },
      json: true
    });

    const allCategories = data.results || [];

    // Filtrăm local după search term (dacă există)
    const filtered = searchTerm
      ? allCategories.filter(c =>
          (c.name || '').toLowerCase().includes(searchTerm)
        )
      : allCategories;

    categories = filtered
      .slice(0, MAX_RESULTS)
      .map(c => ({
        id: String(c.id),
        name: c.name || `Categorie ${c.id}`
      }));

  } else if (platform === 'trendyol') {
    // ── Trendyol API ────────────────────────────────────────────────
    const supplierId = $env['TRENDYOL_SUPPLIER_ID'] || '';
    const apiKey    = $env['TRENDYOL_API_KEY']    || '';
    const apiSecret = $env['TRENDYOL_API_SECRET'] || '';
    const authHeader = 'Basic ' + Buffer.from(`${apiKey}:${apiSecret}`).toString('base64');

    // Trendyol returnează tot arborele de categorii
    const data = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.trendyol.com/sapigw/product/categories',
      headers: {
        'Authorization': authHeader,
        'User-Agent': `${supplierId} - SelfIntegration`,
        'Accept': 'application/json'
      },
      json: true
    });

    // Aplatizăm arborele recursiv
    function flattenCategories(nodes, result = []) {
      for (const node of (nodes || [])) {
        result.push({ id: String(node.id), name: node.name });
        if (node.subCategories && node.subCategories.length) {
          flattenCategories(node.subCategories, result);
        }
      }
      return result;
    }

    const allCategories = flattenCategories(data.categories || []);

    const filtered = searchTerm
      ? allCategories.filter(c =>
          (c.name || '').toLowerCase().includes(searchTerm)
        )
      : allCategories;

    categories = filtered.slice(0, MAX_RESULTS);

  } else if (platform === 'temu') {
    // ── Temu — placeholder ──────────────────────────────────────────
    // Adaptează după integrarea ta Temu.
    const temuCategories = [
      { id: 'temu-1', name: 'Electronice' },
      { id: 'temu-2', name: 'Îmbrăcăminte & Modă' },
      { id: 'temu-3', name: 'Casă & Grădină' },
      { id: 'temu-4', name: 'Sport & Outdoor' },
      { id: 'temu-5', name: 'Jucării & Copii' },
      { id: 'temu-6', name: 'Frumusețe & Îngrijire' },
      { id: 'temu-7', name: 'Auto & Moto' },
      { id: 'temu-8', name: 'Birotică & Papetărie' },
      { id: 'temu-9', name: 'Animale de Companie' },
      { id: 'temu-10', name: 'Alimentar & Gourmet' }
    ];

    const filtered = searchTerm
      ? temuCategories.filter(c =>
          c.name.toLowerCase().includes(searchTerm)
        )
      : temuCategories;

    categories = filtered.slice(0, MAX_RESULTS);
  }

} catch (err) {
  console.error(`[v2-all-categories] Eroare pentru ${platform}:`, err.message);
  return [{ json: { categories: [], error: err.message } }];
}

return [{ json: { categories } }];
